use MyApp.Accounts.User

def update(conn, params) do
  user = get_user(conn) # Get user from context

  changeset = User.changeset(user, params)
  case Ecto.Changeset.validate(changeset) do
    {:ok, %User{} = user} ->
      {:ok, user}
    {:error, errors} ->
      conn
      |> put_flash(:error, errors)
      |> render(MyApp.Accounts.templates.edit, assigns: [user: user, errors: errors])
  end
end